CREATE TABLE document_proposals(proposal_id TEXT PRIMARY KEY CHECK(length(proposal_id) BETWEEN 1 AND 128),project_id TEXT NOT NULL REFERENCES projects(id),connector_id TEXT NOT NULL REFERENCES outline_connections(connector_id),connector_epoch INTEGER NOT NULL CHECK(connector_epoch>0),document_id TEXT NOT NULL CHECK(length(document_id) BETWEEN 1 AND 128),run_id TEXT NOT NULL REFERENCES agent_runs(id),attempt_id TEXT NOT NULL REFERENCES execution_attempts(id),base_revision TEXT NOT NULL CHECK(length(base_revision) BETWEEN 1 AND 256),base_digest TEXT NOT NULL CHECK(length(base_digest)=64),authored_patch TEXT NOT NULL CHECK(length(CAST(authored_patch AS BLOB)) BETWEEN 1 AND 131072),authored_patch_digest TEXT NOT NULL CHECK(length(authored_patch_digest)=64),created_at INTEGER NOT NULL CHECK(created_at>=0)) STRICT;
CREATE TABLE document_conflicts(conflict_id TEXT PRIMARY KEY CHECK(length(conflict_id) BETWEEN 1 AND 128),proposal_id TEXT NOT NULL REFERENCES document_proposals(proposal_id),current_revision TEXT NOT NULL,current_digest TEXT NOT NULL CHECK(length(current_digest)=64),detected_at INTEGER NOT NULL CHECK(detected_at>=0),UNIQUE(proposal_id,current_revision,current_digest)) STRICT;
CREATE TABLE document_proposal_decisions(decision_id TEXT PRIMARY KEY,proposal_id TEXT NOT NULL REFERENCES document_proposals(proposal_id),decision_revision INTEGER NOT NULL CHECK(decision_revision>0),decision TEXT NOT NULL CHECK(decision IN ('APPLY','REJECT','CONFLICT')),member_id TEXT REFERENCES members(id),provider_revision TEXT,decided_at INTEGER NOT NULL CHECK(decided_at>=0),UNIQUE(proposal_id,decision_revision)) STRICT;
CREATE TABLE external_working_documents(working_document_id TEXT PRIMARY KEY,project_id TEXT NOT NULL REFERENCES projects(id),connector_id TEXT NOT NULL REFERENCES outline_connections(connector_id),connector_epoch INTEGER NOT NULL CHECK(connector_epoch>0),run_id TEXT NOT NULL UNIQUE REFERENCES agent_runs(id),attempt_id TEXT NOT NULL REFERENCES execution_attempts(id),document_id TEXT NOT NULL,current_revision TEXT NOT NULL,current_digest TEXT NOT NULL CHECK(length(current_digest)=64),enable_approval_id TEXT NOT NULL,lifecycle_revision INTEGER NOT NULL CHECK(lifecycle_revision>0),created_at INTEGER NOT NULL CHECK(created_at>=0)) STRICT;
CREATE TABLE working_document_dispositions(id TEXT PRIMARY KEY,working_document_id TEXT NOT NULL REFERENCES external_working_documents(working_document_id),expected_lifecycle_revision INTEGER NOT NULL CHECK(expected_lifecycle_revision>0),disposition TEXT NOT NULL CHECK(disposition IN ('KEEP','PROMOTE','ARCHIVE')),actor_member_id TEXT NOT NULL REFERENCES members(id),resulting_revision TEXT,created_at INTEGER NOT NULL CHECK(created_at>=0),UNIQUE(working_document_id,expected_lifecycle_revision)) STRICT;
INSERT INTO schema_migrations(version,applied_at) VALUES(12,CAST(strftime('%s','now') AS INTEGER)*1000);
